async def validate_bearer_token(
    credentials: Optional[HTTPAuthorizationCredentials] = Depends(security_scheme),
    redis_client: redis.Redis = Depends(get_redis),
) -> TokenData:
    if credentials is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Missing authorization header",
            headers={"WWW-Authenticate": "Bearer"},
        )

    token = credentials.credentials

    if not token or len(token) < 10:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token format",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    redis_key = f"{TOKEN_PREFIX}{token}"

    try:
        token_data_raw = await redis_client.get(redis_key)
    except redis.RedisError as e:
        logger.error(f"Redis error during token validation: {e}")
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Token validation service temporarily unavailable",
        )

    if token_data_raw is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token not found or expired",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    try:
        token_dict = json.loads(token_data_raw)
        token_data = TokenData(**token_dict)
    except (json.JSONDecodeError, ValueError) as e:
        logger.error(f"Failed to parse token data: {e}")
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Corrupted token data",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    expires_at = datetime.fromisoformat(token_data.expires_at)
    if datetime.utcnow() > expires_at:
        await redis_client.delete(redis_key)
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token has expired",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    return token_data


def require_scopes(*required_scopes: str):
    async def scope_validator(
        token_data: TokenData = Depends(validate_bearer_token),
    ) -> TokenData:
        for scope in required_scopes:
            if scope not in token_data.scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient scope. Required: {required_scopes}, "
                           f"granted: {token_data.scopes}",
                    headers={
                        "WWW-Authenticate": f'Bearer error="insufficient_scope" '
                                            f'scope="{" ".join(required_scopes)}"'
                    },
                )
        return token_data

    return scope_validator


@app.get("/health", response_model=HealthResponse, tags=["System"])
async def health_check():
    redis_connected = False
    try:
        client = await get_redis()
        await client.ping()
        redis_connected = True
    except Exception as e:
        logger.warning(f"Redis health check failed: {e}")

    return HealthResponse(
        status="healthy" if redis_connected else "degraded",
        redis_connected=redis_connected,
        timestamp=datetime.utcnow().isoformat(),
    )


@app.post("/admin/tokens", response_model=TokenInfo, tags=["Admin"])
async def create_token(
    request: TokenCreateRequest,
    redis_client: redis.Redis = Depends(get_redis),
):
    access_token = secrets.token_urlsafe(48)

    now = datetime.utcnow()
    expires_at = now + timedelta(seconds=request.expires_in)

    token_data = TokenData(
        user_id=request.user_id,
        email=request.email,
        scopes=request.scopes,
        client_id=request.client_id,
        issued_at=now.isoformat(),
        expires_at=expires_at.isoformat(),
    )

    redis_key = f"{TOKEN_PREFIX}{access_token}"

    try:
        await redis_client.setex(
            redis_key,
            request.expires_in,
            token_data.model_dump_json(),
        )
    except redis.RedisError as e:
        logger.error(f"Failed to store token in Redis: {e}")
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Failed to create token",
        )

    logger.info(f"Token created for user {request.user_id} with scopes {request.scopes}")

    return TokenInfo(
        access_token=access_token,
        token_type="bearer",
        expires_in=request.expires_in,
        user_id=request.user_id,
        scopes=request.scopes,
    )


@app.delete("/admin/tokens/{token}", tags=["Admin"])
async def revoke_token(
    token: str,
    redis_client: redis.Redis = Depends(get_redis),
):
    redis_key = f"{TOKEN_PREFIX}{token}"

    try:
        deleted = await redis_client.delete(redis_key)
    except redis.RedisError as e:
        logger.error(f"Failed to revoke token: {e}")
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Failed to revoke token",
        )

    if deleted == 0:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail="Token not found",
        )

    logger.info("Token revoked successfully")
    return {"message": "Token revoked successfully"}


